dec:
padding-left: 0;
  margin-top: var(--doc-body-spacing);
  margin-bottom: calc(var(--doc-body-spacing) * 2);
  list-style-type: none;
  counter-reset: item;

font-family: var(--doc-font-body-text);
  font-size: var(--doc-body-size);
  color: var(--doc-primary-color);
  line-height: var(--doc-body-line-height);
  margin-bottom: var(--doc-body-spacing);
  padding-left: var(--doc-list-indent);
  text-indent: calc(var(--doc-list-indent) * -1);
  font-style: normal;
  position: relative;
  text-align: var(--doc-body-align);

font-family: var(--doc-font-list-item);
  counter-increment: item;
  content: "[" counter(item) "] ";
  font-weight: 700;
  color: var(--doc-primary-color);
  margin-right: 6pt;
  display: inline-block;
  text-indent: 0;
